  1	import { useState, FC, KeyboardEvent } from 'react';
  2	
  3	import { RESTApi } from '@API/REST.api';
  4	import { I18nNamespace } from '@config/config';
  5	import { TooltipInfoButton } from '@core/components/HelpTooltip';
  6	import { createListenerRequest } from '@core/utils/createCRD';
  7	import useValidatedInput from '@hooks/useValidation';
  8	import { ListenerCrdParams, ListenerSpec } from '@interfaces/CRD_Listener';
  9	import { HTTPError } from '@interfaces/REST.interfaces';
 10	import {
 11	  Form,
 12	  FormGroup,
 13	  TextInput,
 14	  ActionGroup,
 15	  Button,
 16	  FormAlert,
 17	  Alert,
 18	  Title,
 19	  Card,
 20	  CardTitle,
 21	  CardBody
 22	} from '@patternfly/react-core';
 23	import { useMutation } from '@tanstack/react-query';
 24	import { useTranslation } from 'react-i18next';
 25	
 26	interface ListenerCrdAttributes extends ListenerSpec {
 27	  name?: string;
 28	  resourceVersion?: string;
 29	}
 30	
 31	const ListenerForm: FC<{
 32	  onSubmit: () => void;
 33	  onCancel: () => void;
 34	  title: string;
 35	  listenerName?: string;
 36	  attributes?: ListenerCrdAttributes;
 37	}> = function ({ onSubmit, onCancel, listenerName, attributes, title }) {
 38	  const { t } = useTranslation(I18nNamespace);
 39	
 40	  const [name, setName] = useState(attributes?.name || '');
 41	  const [routingKey, setRoutingKey] = useState(attributes?.routingKey || '');
 42	  const [host, setHost] = useState(attributes?.host || '');
 43	  const [port, setPort] = useState<string | number>(attributes?.port || '');
 44	  const [tlsCredentials, setTlsCredentials] = useState(attributes?.tlsCredentials || '');
 45	
 46	  const { validated, validateInput } = useValidatedInput();
 47	
 48	  const mutationCreate = useMutation({
 49	    mutationFn: (data: ListenerCrdParams) => RESTApi.createOrUpdateListener(data, listenerName),
 50	    onError: (data: HTTPError) => {
 51	      validateInput(data.descriptionMessage);
 52	    },
 53	    onSuccess: onSubmit
 54	  });
 55	
 56	  const handleSubmit = () => {
 57	    const data: ListenerCrdParams = createListenerRequest({
 58	      metadata: {
 59	        name,
 60	        resourceVersion: attributes?.resourceVersion
 61	      },
 62	      spec: {
 63	        routingKey,
 64	        host,
 65	        port: Number(port),
 66	        tlsCredentials
 67	      }
 68	    });
 69	
 70	    mutationCreate.mutate(data);
 71	  };
 72	
 73	  const handleChangeRoutingKey = (value: string) => {
 74	    setRoutingKey(value);
 75	  };
 76	
 77	  const handleChangeServiceName = (value: string) => {
 78	    setHost(value);
 79	  };
 80	
 81	  const handleChangePort = (value: string) => {
 82	    setPort(value);
 83	  };
 84	
 85	  const handleChangeName = (value: string) => {
 86	    setName(value);
 87	  };
 88	
 89	  const handleChangeTlsCredentials = (value: string) => {
 90	    setTlsCredentials(value);
 91	  };
 92	
 93	  const handleKeyPress = (event: KeyboardEvent) => {
 94	    if (event.key === 'Enter' && !!(name && port)) {
 95	      event.preventDefault(); // Prevents the default Enter key behavior
 96	      handleSubmit();
 97	    }
 98	  };
 99	
100	  const canSubmit = !!(name && port);
101	
102	  return (
103	    <Card isPlain>
104	      <CardTitle>
105	        <Title headingLevel="h1">{t(title)}</Title>
106	      </CardTitle>
107	      <CardBody>
108	        <Form isHorizontal onKeyDown={handleKeyPress}>
109	          <FormGroup fieldId="name-input" isRequired label={t('Name')} title="">
110	            <TextInput
111	              isDisabled={!!listenerName}
112	              aria-label="form name input"
113	              value={name}
114	              onChange={(_, value) => handleChangeName(value)}
115	            />
116	          </FormGroup>
117	
118	          <FormGroup
119	            fieldId="port-input"
120	            isRequired
121	            label={t('Port')}
122	            labelIcon={<TooltipInfoButton content={t('tooltipPort')} />}
123	            title=""
124	          >
125	            <TextInput aria-label="form port input" value={port} onChange={(_, value) => handleChangePort(value)} />
126	          </FormGroup>
127	
128	          <FormGroup
129	            fieldId="routing-key-input"
130	            label={t('Routing key')}
131	            labelIcon={<TooltipInfoButton content={t('tooltipRoutingKey')} />}
132	            title=""
133	          >
134	            <TextInput
135	              aria-label="form routing key input"
136	              value={routingKey}
137	              onChange={(_, value) => handleChangeRoutingKey(value)}
138	            />
139	          </FormGroup>
140	
141	          <FormGroup
142	            fieldId="service-name-input"
143	            label={t('Service name')}
144	            labelIcon={<TooltipInfoButton content={t('tooltipListenerHost')} />}
145	          >
146	            <TextInput
147	              aria-label="form service name input"
148	              value={host}
149	              onChange={(_, value) => handleChangeServiceName(value)}
150	            />
151	          </FormGroup>
152	
153	          <FormGroup
154	            fieldId="tls-secret-input"
155	            label={t('TLS secret')}
156	            labelIcon={<TooltipInfoButton content={t('tooltipTlsCredentials')} />}
157	            title=""
158	          >
159	            <TextInput
160	              aria-label="form TLS secret input"
161	              value={tlsCredentials}
162	              onChange={(_, value) => handleChangeTlsCredentials(value)}
163	            />
164	          </FormGroup>
165	
166	          {validated && (
167	            <FormAlert>
168	              <Alert variant="danger" title={t('An error occurred')} aria-live="polite" isInline>
169	                {validated}
170	              </Alert>
171	            </FormAlert>
172	          )}
173	
174	          <ActionGroup style={{ display: 'flex' }}>
175	            <Button variant="primary" onClick={handleSubmit} isDisabled={!canSubmit}>
176	              {t('Submit')}
177	            </Button>
178	            <Button variant="link" onClick={onCancel}>
179	              {t('Cancel')}
180	            </Button>
181	          </ActionGroup>
182	        </Form>
183	      </CardBody>
184	    </Card>
185	  );
186	};
187	
188	export default ListenerForm;

